// Function declaration (hoisted -- can be called before it is defined)
function add(a, b) {
  return a + b;
}

// Arrow function (not hoisted, more concise)
const multiply = (a, b) => a * b;

// Arrow function with body
const divide = (a, b) => {
  if (b === 0) throw new Error('Cannot divide by zero');
  return a / b;
};

// Default parameters
function greet(name = 'World') {
  return `Hello, ${name}!`;
}
greet();        // 'Hello, World!'
greet('Alice'); // 'Hello, Alice!'

// Rest parameters (collect remaining arguments into an array)
function sum(...numbers) {
  return numbers.reduce((total, n) => total + n, 0);
}
sum(1, 2, 3, 4); // 10

// Higher-order functions (functions that take or return functions)
function createMultiplier(factor) {
  return (number) => number * factor; // This inner function is a closure
}

const double = createMultiplier(2);
const triple = createMultiplier(3);
double(5); // 10
triple(5); // 15

// Closure: the inner function remembers 'factor' even after
// createMultiplier has finished executing. This is a closure.

// Closure pattern: private state
function createCounter() {
  let count = 0; // private -- no code outside can access this directly

  return {
    increment() { count += 1; },
    decrement() { count -= 1; },
    getCount()  { return count; },
  };
}

const counter = createCounter();
counter.increment();
counter.increment();
counter.getCount(); // 2
// counter.count; // undefined -- cannot access directly

// Closure pattern: event handler factory
function createClickHandler(buttonName) {
  let clickCount = 0;
  return () => {
    clickCount += 1;
    console.log(`${buttonName} clicked ${clickCount} times`);
  };
}

const handleSaveClick = createClickHandler('Save');
// handleSaveClick() -> 'Save clicked 1 times'
// handleSaveClick() -> 'Save clicked 2 times'
